#if UNITY_EDITOR
using System.Collections.Generic;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado de MissionData (Sistema de Missões — Missão &gt; Tarefa,
/// tarefas não-lineares):
///
/// 1) Inspector padrão (todos os campos).
/// 2) Avisos de validação locais: "missionId"/"displayName" vazios (IDs
///    duplicados/em falta entre TODAS as missões já são verificados
///    globalmente por "Animals/Validar Dados do Jogo" — GameDataValidatorWindow),
///    tarefas com descrição vazia, "Task Id" repetidos, "Depends On Task Ids"
///    que apontam para "Task Ids" inexistentes nesta missão ou dependências
///    circulares, "completionMessage" vazio (usa o texto genérico "MISSÃO
///    CONCLUÍDA").
/// 3) Em Play Mode: mostra o estado de cada tarefa (Concluída/Activa/Bloqueada,
///    via MissionManager), para conferir rapidamente o progresso sem abrir o
///    Diário.
/// </summary>
[CustomEditor(typeof(MissionData))]
public class MissionDataEditor : Editor
{
    public override void OnInspectorGUI()
    {
        serializedObject.Update();
        var mission = (MissionData)target;

        DrawDefaultInspector();

        EditorGUILayout.Space();
        DrawValidationWarnings(mission);

        if (Application.isPlaying)
        {
            EditorGUILayout.Space();
            DrawRuntimeState(mission);
        }
    }

    private void DrawValidationWarnings(MissionData mission)
    {
        EditorGUILayout.LabelField("Validação", EditorStyles.boldLabel);

        bool anyWarning = false;

        if (string.IsNullOrEmpty(mission.missionId))
        {
            EditorGUILayout.HelpBox("\"missionId\" está vazio — necessário para derivar as variáveis \"Missao_<id>_Iniciada\"/\"Missao_<id>_Concluida\"/\"Missao_<id>_Tarefa_<taskId>_Concluida\".", MessageType.Warning);
            anyWarning = true;
        }

        if (string.IsNullOrEmpty(mission.displayName))
        {
            EditorGUILayout.HelpBox("\"displayName\" está vazio — usado no Diário e no banner \"MISSÃO CONCLUÍDA\".", MessageType.Warning);
            anyWarning = true;
        }

        if (mission.tasks != null && mission.tasks.Count > 0)
        {
            var idToTask = new Dictionary<string, MissionTask>();
            var idCounts = new Dictionary<string, int>();

            for (int i = 0; i < mission.tasks.Count; i++)
            {
                var task = mission.tasks[i];
                if (task == null) continue;

                if (string.IsNullOrEmpty(task.description))
                {
                    EditorGUILayout.HelpBox($"Tarefa #{i + 1} não tem \"description\" — o Diário não mostrará nada para esta tarefa.", MessageType.Warning);
                    anyWarning = true;
                }

                string id = mission.EffectiveTaskId(task);
                idCounts[id] = idCounts.TryGetValue(id, out var count) ? count + 1 : 1;

                // Em caso de "Task Id" repetido, fica registada a última tarefa
                // com esse id — o aviso de repetição abaixo já cobre o problema.
                idToTask[id] = task;
            }

            foreach (var kvp in idCounts)
            {
                if (kvp.Value > 1)
                {
                    EditorGUILayout.HelpBox($"\"Task Id\" \"{kvp.Key}\" está repetido em {kvp.Value} tarefas — dá um \"Task Id\" próprio a cada uma (campo \"Task Id\", deixar vazio só funciona para uma delas).", MessageType.Warning);
                    anyWarning = true;
                }
            }

            for (int i = 0; i < mission.tasks.Count; i++)
            {
                var task = mission.tasks[i];
                if (task == null || task.dependsOnTaskIds == null) continue;

                string id = mission.EffectiveTaskId(task);

                foreach (var dependencyId in task.dependsOnTaskIds)
                {
                    if (string.IsNullOrEmpty(dependencyId)) continue;

                    if (dependencyId == id)
                    {
                        EditorGUILayout.HelpBox($"Tarefa \"{id}\" (#{i + 1}) não pode depender de si própria em \"Depends On Task Ids\".", MessageType.Warning);
                        anyWarning = true;
                    }
                    else if (!idToTask.ContainsKey(dependencyId))
                    {
                        EditorGUILayout.HelpBox($"Tarefa \"{id}\" (#{i + 1}) depende do \"Task Id\" \"{dependencyId}\", que não existe nesta missão — esta dependência será ignorada.", MessageType.Warning);
                        anyWarning = true;
                    }
                }
            }

            var cycle = FindDependencyCycle(idToTask);
            if (cycle != null)
            {
                EditorGUILayout.HelpBox($"Dependência circular entre tarefas: {string.Join(" -> ", cycle)}. Estas tarefas nunca ficarão activas — revê \"Depends On Task Ids\".", MessageType.Error);
                anyWarning = true;
            }
        }
        else
        {
            EditorGUILayout.HelpBox("Sem \"tasks\" definidas — esta missão funciona apenas como \"interruptor\" (iniciada/concluída), sem progresso intermédio. Usa Action_CompleteMission para concluir directamente. Se quiseres progresso no Diário (com dependências entre tarefas), adiciona tarefas.", MessageType.Info);
        }

        if (string.IsNullOrEmpty(mission.completionMessage))
        {
            EditorGUILayout.HelpBox("\"completionMessage\" vazio — o banner de conclusão mostrará o texto genérico \"MISSÃO CONCLUÍDA\".", MessageType.None);
        }

        if (mission.completionMusic == null)
        {
            EditorGUILayout.HelpBox("\"completionMusic\" vazio — o banner de conclusão tocará apenas o som padrão (se configurado em MissionCompleteUI), sem sting próprio.", MessageType.None);
        }

        if (!anyWarning && string.IsNullOrEmpty(mission.description))
        {
            EditorGUILayout.HelpBox("Sugestão: preenche \"description\" para referência interna.", MessageType.None);
        }
    }

    private void DrawRuntimeState(MissionData mission)
    {
        EditorGUILayout.LabelField("Estado (Play Mode)", EditorStyles.boldLabel);

        var mm = MissionManager.Instance;
        if (mm == null)
        {
            EditorGUILayout.HelpBox("MissionManager.Instance não encontrado.", MessageType.None);
            return;
        }

        bool started = mm.IsMissionStarted(mission);
        bool completed = mm.IsMissionCompleted(mission);

        EditorGUILayout.LabelField("Iniciada", started ? "Sim" : "Não");
        EditorGUILayout.LabelField("Concluída", completed ? "Sim" : "Não");

        if (mission.tasks != null && mission.tasks.Count > 0)
        {
            EditorGUILayout.Space();
            EditorGUILayout.LabelField("Tarefas", EditorStyles.boldLabel);

            foreach (var task in mission.tasks)
            {
                if (task == null) continue;

                string id = mission.EffectiveTaskId(task);
                string description = !string.IsNullOrEmpty(task.description) ? task.description : "(sem descrição)";

                string state;
                if (mm.IsTaskCompleted(mission, task)) state = "Concluída";
                else if (mm.IsTaskActive(mission, task)) state = "Activa";
                else state = "Bloqueada";

                EditorGUILayout.LabelField(id, $"{state} — {description}");
            }
        }
    }

    /// <summary>
    /// Procura um ciclo de dependências em "Depends On Task Ids" (DFS). Devolve
    /// a lista de "Task Ids" do ciclo encontrado (ex: ["a", "b", "c", "a"]), ou
    /// null se não houver nenhum.
    /// </summary>
    private static List<string> FindDependencyCycle(Dictionary<string, MissionTask> idToTask)
    {
        var visited = new HashSet<string>();
        var stack = new List<string>();

        foreach (var id in idToTask.Keys)
        {
            var cycle = Visit(id);
            if (cycle != null) return cycle;
        }

        return null;

        List<string> Visit(string id)
        {
            int stackIndex = stack.IndexOf(id);
            if (stackIndex >= 0)
            {
                var result = stack.GetRange(stackIndex, stack.Count - stackIndex);
                result.Add(id);
                return result;
            }

            if (visited.Contains(id)) return null;
            visited.Add(id);

            if (!idToTask.TryGetValue(id, out var task) || task.dependsOnTaskIds == null) return null;

            stack.Add(id);

            foreach (var dependencyId in task.dependsOnTaskIds)
            {
                if (string.IsNullOrEmpty(dependencyId) || !idToTask.ContainsKey(dependencyId)) continue;

                var cycle = Visit(dependencyId);
                if (cycle != null) return cycle;
            }

            stack.RemoveAt(stack.Count - 1);
            return null;
        }
    }
}
#endif
